  4	import { useTranslation } from 'react-i18next';
  5	import {
  6	  getGroupVersionKindForModel,
  7	  useAccessReview,
  8	  useAnnotationsModal,
  9	  useDeleteModal,
 10	  useK8sWatchResource,
 11	  useLabelsModal,
 12	  useModal,
 13	} from '@openshift-console/dynamic-plugin-sdk';
 14	import { PipelineModel, PipelineRunModel } from '../../models';
 15	import { LoadingBox } from '../status/status-box';
 16	import DetailsPage from '../details-page/DetailsPage';
 17	import { navFactory } from '../utils/horizontal-nav';
 18	import ResourceYAMLEditorTab from '../yaml-editor/ResourceYAMLEditorTab';
 19	import PipelineDetails from './PipelineDetails';
 20	import { PipelineKind, PipelineRunKind } from '../../types';
 21	import { getReferenceForModel } from '../pipelines-overview/utils';
 22	import PipelineParamatersTab from './PipelineParamatersTab';
 23	import { useGetActiveUser, useLatestPipelineRun } from '../hooks/hooks';
 24	import { rerunPipeline } from '../utils/pipelines-actions';
 25	import _ from 'lodash';
 26	import {
 27	  AddTriggerModal,
 28	  RemoveTriggerModal,
 29	  startPipelineModal,
 30	} from '../start-pipeline';
 31	import { triggerPipeline } from '../pipelines-list/PipelineKebab';
 32	import { StartedByAnnotation } from '../../consts';
 33	import { usePipelineTriggerTemplateNames } from '../utils/triggers';
 34	import { resourcePathFromModel } from '../utils/utils';
 35	import { ErrorPage404 } from '../common/error';
 36	
 37	const PipelineDetailsPage = () => {
 38	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 39	  const params = useParams();
 40	  const navigate = useNavigate();
 41	  const currentUser = useGetActiveUser();
 42	  const { name, ns: namespace } = params;
 43	  const [pipeline, loaded, loadError] = useK8sWatchResource<PipelineKind>({
 44	    groupVersionKind: getGroupVersionKindForModel(PipelineModel),
 45	    namespace,
 46	    name,
 47	  });
 48	  const launchModal = useModal();
 49	  const latestPipelineRun = useLatestPipelineRun(name, namespace);
 50	  const launchAnnotationsModal = useAnnotationsModal(pipeline);
 51	  const launchLabelsModal = useLabelsModal(pipeline);
 52	  const launchDeleteModal = useDeleteModal(pipeline);
 53	  const templateNames = usePipelineTriggerTemplateNames(name, namespace) || [];
 54	  const canEditResource = useAccessReview({
 55	    group: PipelineModel.apiGroup,
 56	    resource: PipelineModel.plural,
 57	    verb: 'update',
 58	    name,
 59	    namespace,
 60	  });
 61	  const canDeleteResource = useAccessReview({
 62	    group: PipelineModel.apiGroup,
 63	    resource: PipelineModel.plural,
 64	    verb: 'delete',
 65	    name,
 66	    namespace,
 67	  });
 68	
 69	  const editURL = `/k8s/ns/${namespace}/${getReferenceForModel(
 70	    PipelineModel,
 71	  )}/${encodeURIComponent(name)}/builder`;
 72	
 73	  const resourceTitleFunc = React.useMemo(() => {
 74	    return (
 75	      <div className="Pipeline-details-page">{pipeline?.metadata?.name} </div>
 76	    );
 77	  }, [pipeline]);
 78	
 79	  const handlePipelineRunSubmit = (pipelineRun: PipelineRunKind) => {
 80	    navigate(
 81	      resourcePathFromModel(
 82	        PipelineRunModel,
 83	        pipelineRun.metadata.name,
 84	        pipelineRun.metadata.namespace,
 85	      ),
 86	    );
 87	  };
 88	
 89	  const startPipeline = () => {
 90	    const params = _.get(pipeline, ['spec', 'params'], []);
 91	    const resources = _.get(pipeline, ['spec', 'resources'], []);
 92	    const workspaces = _.get(pipeline, ['spec', 'workspaces'], []);
 93	
 94	    if (!_.isEmpty(params) || !_.isEmpty(resources) || !_.isEmpty(workspaces)) {
 95	      launchModal(startPipelineModal, {
 96	        pipeline,
 97	        onSubmit: handlePipelineRunSubmit,
 98	      });
 99	    } else {
100	      triggerPipeline(pipeline, currentUser, handlePipelineRunSubmit);
101	    }
102	  };
103	
104	  const rerunPipelineAndRedirect = () => {
105	    rerunPipeline(
106	      PipelineRunModel,
107	      latestPipelineRun,
108	      currentUser,
109	      launchModal,
110	      {
111	        onComplete: handlePipelineRunSubmit,
112	      },
113	    );
114	  };
115	
116	  const addTrigger = () => {
117	    const cleanPipeline: PipelineKind = {
118	      ...pipeline,
119	      metadata: {
120	        ...pipeline.metadata,
121	        annotations: _.omit(pipeline.metadata.annotations, [
122	          StartedByAnnotation.user,
123	        ]),
124	      },
125	    };
126	    launchModal(AddTriggerModal, { pipeline: cleanPipeline });
127	  };
128	
129	  const removeTrigger = () => {
130	    launchModal(RemoveTriggerModal, { pipeline });
131	  };
132	
133	  if (!loaded) {
134	    return loadError ? <ErrorPage404 /> : <LoadingBox />;
135	  }
136	  return (
137	    <DetailsPage
138	      obj={pipeline}
139	      headTitle={name}
140	      title={<Text component={TextVariants.h1}>{resourceTitleFunc}</Text>}
141	      model={PipelineModel}
142	      breadcrumbs={[
143	        <BreadcrumbItem key="app-link" component="div">
144	          <Link
145	            data-test="breadcrumb-link"
146	            className="pf-v6-c-breadcrumb__link"
147	            to={`/pipelines/ns/${namespace}/`}
148	          >
149	            {t('Pipelines')}
150	          </Link>
151	        </BreadcrumbItem>,
152	        {
153	          path: `/pipelines/ns/${namespace}/`,
154	          name: t('Pipeline details'),
155	        },
156	      ]}
157	      pages={[
158	        navFactory.details(PipelineDetails),
159	        navFactory.editYaml(ResourceYAMLEditorTab),
160	        {
161	          href: 'parameters',
162	          name: t('Parameters'),
163	          component: PipelineParamatersTab,
164	        },
165	      ]}
166	      actions={[
167	        {
168	          key: 'start-pipeline',
169	          label: t('Start'),
170	          onClick: startPipeline,
171	        },
172	        ...(latestPipelineRun
173	          ? [
174	              {
175	                key: 'start-last-run',
176	                label: t('Start last run'),
177	                onClick: rerunPipelineAndRedirect,
178	                disabled: !canEditResource[0],
179	              },
180	            ]
181	          : []),
182	        {
183	          key: 'add-trigger',
184	          label: t('Add Trigger'),
185	          onClick: addTrigger,
186	        },
187	        ...(templateNames.length > 0
188	          ? [
189	              {
190	                key: 'remove-trigger',
191	                label: t('Remove Trigger'),
192	                onClick: removeTrigger,
193	              },
194	            ]
195	          : []),
196	        {
197	          key: 'edit-labels',
198	          label: t('Edit labels'),
199	          onClick: () => launchLabelsModal(),
200	          disabled: !canEditResource[0],
201	        },
202	        {
203	          key: 'edit-annotations',
204	          label: t('Edit annotations'),
205	          onClick: () => launchAnnotationsModal(),
206	          disabled: !canEditResource[0],
207	        },
208	        {
209	          key: 'edit-task',
210	          label: t('Edit {{resourceKind}}', {
211	            resourceKind: PipelineModel.kind,
212	          }),
213	          onClick: () => navigate(editURL),
214	          disabled: !canEditResource[0],
215	        },
216	        {
217	          key: 'delete-task',
218	          label: t('Delete {{resourceKind}}', {
219	            resourceKind: PipelineModel.kind,
220	          }),
221	          onClick: () => launchDeleteModal(),
222	          disabled: !canDeleteResource[0],
223	        },
224	      ]}
225	    />
226	  );
227	};
228	
229	export default PipelineDetailsPage;

